  ('real-estate-moex-01922', 'real-estate', 'real-estate-moex-101-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '依公平交易法規定，損害賠償請求權，自請求權人知有行為及賠償義務人時起，多久期間不行使而消滅？', '["半年", "一年", "一年半", "二年"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:10+00:00", "source_pdf_sha1": "19eb034796e3", "answer_pdf_sha1": "fc61af395efe", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01923', 'real-estate', 'real-estate-moex-101-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '依公平交易法所處停止營業之期間，每次以多久期間為限？', '["一個月", "三個月", "六個月", "十二個月"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:10+00:00", "source_pdf_sha1": "19eb034796e3", "answer_pdf_sha1": "fc61af395efe", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01924', 'real-estate', 'real-estate-moex-101-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '下列敘述何者為錯誤？', '["直轄市或縣（市）主管機關得選擇特定行業，公告規定其定型化契約應記載或不得記載之事項，違反 該公告之定型化契約，其定型化契約條款無效", "定型化契約中之條款違反誠信原則，對消費者顯失公平者，無效", "定型化契約中之定型化契約條款牴觸個別磋商條款之約定者，其牴觸部分無效", "定型化契約中之定型化契約條款，全部或一部無效或不構成契約內容之一部者，除去該部分，契約亦 可成立者，該契約之其他部分，仍為有效。但對當事人之一方顯失公平者，該契約全部無效"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:10+00:00", "source_pdf_sha1": "19eb034796e3", "answer_pdf_sha1": "fc61af395efe", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01925', 'real-estate', 'real-estate-moex-101-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '有關預售屋買賣定型化契約應記載事項，下列何者為錯誤？', '["賣方應確保廣告內容之真實，預售屋之廣告宣傳品及其所記載之建材設備表、房屋及停車位平面圖與 位置示意圖，為契約之一部分", "附屬建物，除陽臺外，其餘項目不得計入買賣價格", "房屋所有權之移轉，應於使用執照核發後三個月內備妥文件申辦有關稅費及權利移轉登記", "賣方應於領得使用執照六個月內，通知買方進行交屋"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:10+00:00", "source_pdf_sha1": "19eb034796e3", "answer_pdf_sha1": "fc61af395efe", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01926', 'real-estate', 'real-estate-moex-101-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '有關不動產委託銷售定型化契約之應記載事項，下列敘述何者錯誤？', '["委託銷售價格未記載金額者，不動產委託銷售定型化契約無效", "未記載委託銷售期間者，委託人得隨時以書面終止", "受託人受託處理仲介事務應以善良管理人之注意為之", "受託人於簽約前，應據實提供該公司（或商號）近一個月之成交行情，供委託人訂定售價之參考；如 有隱匿不實，應負賠償責任"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:10+00:00", "source_pdf_sha1": "19eb034796e3", "answer_pdf_sha1": "fc61af395efe", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01927', 'real-estate', 'real-estate-moex-101-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '有關不動產說明書「成屋」之應記載事項，下列何者非屬「建築改良物瑕疵情形」？', '["是否為凶宅", "是否有滲漏水情形及其位置", "是否有損鄰狀況", "是否有檢測海砂含氯量及輻射鋼筋"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:10+00:00", "source_pdf_sha1": "19eb034796e3", "answer_pdf_sha1": "fc61af395efe", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01928', 'real-estate', 'real-estate-moex-101-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '有關不動產說明書「土地」之應記載事項，其應納稅額不包含下列何種稅目？', '["土地增值稅", "地價稅", "契稅", "印花稅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:10+00:00", "source_pdf_sha1": "19eb034796e3", "answer_pdf_sha1": "fc61af395efe", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01929', 'real-estate', 'real-estate-moex-101-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '下列敘述何者為錯誤？', '["經紀業應將其仲介或代銷相關證照及許可文件連同經紀人證書揭示於營業處所明顯之處；其為加盟經 營者，應併標明之", "經營仲介業務者應揭示報酬標準及收取方式於營業處所明顯之處", "經紀業或經紀人員不得收取差價或其他報酬，其經營仲介業務者，並應依實際成交價金或租金按中央 主管機關規定之報酬標準計收", "違反收取差價或其他報酬禁止規定者，其已收取之差價或其他報酬，應全額加計利息後返還支付人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:10+00:00", "source_pdf_sha1": "19eb034796e3", "answer_pdf_sha1": "fc61af395efe", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01930', 'real-estate', 'real-estate-moex-101-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '下列有關營業保證金之敘述，何者為錯誤？', '["由各直轄市或縣（市）政府統一於指定之金融機構設置營業保證金專戶儲存", "經紀業因合併、變更組織時對其所繳存之營業保證金之權利應隨之移轉", "基金管理委員會委員，由經紀業擔任者，其人數不得超過委員總數之五分之二", "基金之孳息部分，得運用於健全不動產經紀制度"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:10+00:00", "source_pdf_sha1": "19eb034796e3", "answer_pdf_sha1": "fc61af395efe", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01931', 'real-estate', 'real-estate-moex-101-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '下列有關申報登錄實際資訊之規定，何者為最正確？', '["經營代銷業務者，對於起造人或建築業委託代銷之案件，應於委託代銷契約屆滿或終止十日內，向主 管機關申報登錄成交案件實際資訊", "已登錄之不動產交易價格資訊，得為課稅依據", "經營仲介業務者，對於買賣或租賃委託案件，應於簽訂買賣契約書並辦竣所有權移轉登記或簽訂租賃 契約書後十日內，向主管機關申報登錄成交案件實際資訊", "登錄之資訊，除涉及個人資料外，得供政府機關利用並以區段化、去識別化方式提供查詢"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:10+00:00", "source_pdf_sha1": "19eb034796e3", "answer_pdf_sha1": "fc61af395efe", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
